```javascript
function solve(nums, edges) {
    const N = nums.length;

    // 1. Build Adjacency Matrix
    const adj = Array(N).fill(0).map(() => Array(N).fill(false));
    for (const [u, v] of edges) {
        adj[u][v] = true;
        adj[v][u] = true;
    }

    let count = 0;
    const numSubsets = 1 << N;

    // Iterate through all non-empty subsets (masks from 1 to 2^N - 1)
    for (let mask = 1; mask < numSubsets; mask++) {

        // --- Check Condition 2: Parity of sum ---
        let sum = 0;
        let nodesInS = [];
        for (let i = 0; i < N; i++) {
            if ((mask >> i) & 1) {
                sum += nums[i];
                nodesInS.push(i);
            }
        }

        if (sum % 2 !== 0) {
            continue; // Fails parity check
        }

        // --- Check Condition 1: Connectivity ---

        // Since mask >= 1, nodesInS is non-empty. Pick the first node as start.
        const startNode = nodesInS[0];

        // Use BFS for connectivity check
        const visited = new Set();
        const queue = [startNode];
        visited.add(startNode);
        let visitedCount = 0;

        let head = 0;
        while (head < queue.length) {
            const u = queue[head++];
            visitedCount++;

            // Check neighbors v
            for (let v = 0; v < N; v++) {
                // 1. Check if v is in S (must be in mask)
                if (((mask >> v) & 1) === 0) {
                    continue;
                }

                // 2. Check if there is an edge (u, v)
                if (!adj[u][v]) {
                    continue;
                }

                // 3. Check if v is not visited
                if (!visited.has(v)) {
                    visited.add(v);
                    queue.push(v);
                }
            }
        }

        // The subgraph is connected if we visited all nodes in S
        if (visitedCount === nodesInS.length) {
            count++;
        }
    }

    return count;
}
